1	import express, { Request, Response, NextFunction } from 'express';
2	import helmet from 'helmet';
3	import compression from 'compression';
4	import swaggerUi from 'swagger-ui-express';
5	import path from 'path';
6	import { auditMiddleware } from './middleware/audit.middleware';
7	import { AppError } from './utils/errors';
8	import { traceStore } from './utils/logger';
9	import { createCategoryLogger } from './utils/logger';
10	import { openApiSpec } from './swagger';
11	import { generalLimiter, authLimiter } from './middleware/rate-limit.middleware';
12	import authRoutes from './routes/auth.routes';
13	import accountsRoutes from './routes/accounts.routes';
14	import usersRoutes from './routes/users.routes';
15	import groupsRoutes from './routes/groups.routes';
16	import itinerariesRoutes from './routes/itineraries.routes';
17	import filesRoutes from './routes/files.routes';
18	import notificationsRoutes from './routes/notifications.routes';
19	import reportsRoutes from './routes/reports.routes';
20	import importRoutes from './routes/import.routes';
21	import faceRoutes from './routes/face.routes';
22	import qualityRoutes from './routes/quality.routes';
23	import auditRoutes from './routes/audit.routes';
24	
25	const systemLogger = createCategoryLogger('system');
26	
27	const app = express();
28	
29	// Security and compression
30	app.use(helmet());
31	app.use(compression());
32	app.use(express.json());
33	app.use(express.urlencoded({ extended: true }));
34	
35	// Trace ID on every request
36	app.use(auditMiddleware);
37	
38	// Health check
39	app.get('/health', (_req: Request, res: Response) => {
40	  res.json({ status: 'ok', timestamp: new Date().toISOString() });
41	});
42	
43	// Swagger UI
44	app.use('/api/docs', swaggerUi.serve, swaggerUi.setup(openApiSpec));
45	
46	// Rate limiting ŌĆö general per-user applied after auth middleware populates user
47	app.use(generalLimiter);
48	
49	// API routes
50	app.use('/auth', authRoutes);
51	app.use('/accounts', accountsRoutes);
52	app.use('/users', usersRoutes);
53	app.use('/groups', groupsRoutes);
54	app.use('/groups/:groupId/itineraries', itinerariesRoutes);
55	app.use('/groups/:groupId/files', filesRoutes);
56	app.use('/notifications', notificationsRoutes);
57	app.use('/reports', reportsRoutes);
58	app.use('/import', importRoutes);
59	app.use('/face', faceRoutes);
60	app.use('/quality', qualityRoutes);
61	app.use('/audit-logs', auditRoutes);
62	
63	// Authenticated export download ŌĆö strict ownership via ExportRecord
64	// Policy: a valid ExportRecord MUST exist. No record = 404 (deny by default).
65	import { authMiddleware as exportAuth, AuthenticatedRequest } from './middleware/auth.middleware';
66	import { ExportRecord } from './models/export.model';
67	app.get('/exports/:filename', exportAuth, async (req: Request, res: Response, next: NextFunction) => {
68	  try {
69	    const filename = path.basename(req.params.filename);
70	
71	    // Reject any path traversal or internal temp artifacts
72	    if (filename.startsWith('.')) {
73	      next(new AppError(404, 'NOT_FOUND', 'Export not found')); return;
74	    }
75	
76	    const record = await ExportRecord.findOne({ where: { filename } });
77	
78	    // No record = deny. Every legitimate export MUST be registered.
79	    if (!record) {
80	      next(new AppError(404, 'NOT_FOUND', 'Export not found')); return;
81	    }
82	
83	    // Expired
84	    if (new Date(record.expires_at) < new Date()) {
85	      next(new AppError(404, 'NOT_FOUND', 'Export has expired')); return;
86	    }
87	
88	    // Ownership: only the creating user or hotel_admin
89	    const authReq = req as AuthenticatedRequest;
90	    if (record.user_id !== authReq.user!.id && authReq.user!.role !== 'hotel_admin') {
91	      next(new AppError(403, 'FORBIDDEN', 'You do not have access to this export')); return;
92	    }
93	
94	    const filePath = path.resolve('exports', filename);
95	    const fs = require('fs');
96	    if (!fs.existsSync(filePath)) { next(new AppError(404, 'NOT_FOUND', 'Export not found or expired')); return; }
97	    res.download(filePath);
98	  } catch (e) { next(e); }
99	});
100	
101	// 404 handler
102	app.use((_req: Request, _res: Response, next: NextFunction) => {
103	  next(new AppError(404, 'NOT_FOUND', 'Resource not found'));
104	});
105	
106	// Global error handler
107	app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
108	  const traceId = traceStore.getStore()?.traceId || 'unknown';
109	
110	  if (err instanceof AppError) {
111	    res.status(err.statusCode).json({
112	      statusCode: err.statusCode,
113	      code: err.code,
114	      message: err.message,
115	      traceId,
116	    });
117	    return;
118	  }
119	
120	  systemLogger.error('unhandled_error', {
121	    error: err.message,
122	    stack: err.stack,
123	  });
124	
125	  res.status(500).json({
126	    statusCode: 500,
127	    code: 'INTERNAL_ERROR',
128	    message: 'Internal server error',
129	    traceId,
130	  });
131	});
132	
133	export default app;
134	
