1	import { Response, NextFunction } from 'express';
2	import { Op, WhereOptions } from 'sequelize';
3	import { AuthenticatedRequest } from '../middleware/auth.middleware';
4	import { AuditLog } from '../models/audit.model';
5	
6	const SENSITIVE_FIELDS = ['password', 'password_hash', 'token', 'accessToken', 'encryption_key', 'secret'];
7	
8	function maskSensitive(obj: unknown): unknown {
9	  if (!obj || typeof obj !== 'object') return obj;
10	  const result: Record<string, unknown> = {};
11	  for (const [k, v] of Object.entries(obj as Record<string, unknown>)) {
12	    if (SENSITIVE_FIELDS.some(f => k.toLowerCase().includes(f))) result[k] = '[REDACTED]';
13	    else result[k] = v;
14	  }
15	  return result;
16	}
17	
18	function buildDateFilter(from?: string, to?: string): Record<symbol, unknown> | undefined {
19	  if (!from && !to) return undefined;
20	  const filter: Record<symbol, unknown> = {};
21	  if (from) filter[Op.gte] = from;
22	  if (to) filter[Op.lte] = to;
23	  return filter;
24	}
25	
26	export async function queryLogs(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
27	  try {
28	    const where: WhereOptions = {};
29	    if (req.query.actorId) (where as any).actor_id = req.query.actorId;
30	    if (req.query.action) (where as any).action = req.query.action;
31	    if (req.query.resourceType) (where as any).resource_type = req.query.resourceType;
32	    const dateFilter = buildDateFilter(req.query.from as string, req.query.to as string);
33	    if (dateFilter) (where as any).created_at = dateFilter;
34	
35	    const page = Math.max(1, parseInt(req.query.page as string) || 1);
36	    const limit = 50;
37	    const { count, rows } = await AuditLog.findAndCountAll({ where, order: [['created_at', 'DESC']], limit, offset: (page - 1) * limit });
38	
39	    res.json({
40	      data: rows.map(r => ({ ...r.toJSON(), detail: maskSensitive(r.detail) })),
41	      pagination: { page, limit, total: count, totalPages: Math.ceil(count / limit) },
42	    });
43	  } catch (e) { next(e); }
44	}
45	
46	export async function exportLogs(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
47	  try {
48	    const where: WhereOptions = {};
49	    const dateFilter = buildDateFilter(req.query.from as string, req.query.to as string);
50	    if (dateFilter) (where as any).created_at = dateFilter;
51	
52	    const rows = await AuditLog.findAll({ where, order: [['created_at', 'DESC']] });
53	    const header = 'id,actor_id,action,resource_type,resource_id,trace_id,ip_address,created_at\n';
54	    const csv = rows.map(r => `${r.id},${r.actor_id || ''},${r.action},${r.resource_type || ''},${r.resource_id || ''},${r.trace_id || ''},${r.ip_address || ''},${r.created_at}`).join('\n');
55	    res.setHeader('Content-Type', 'text/csv');
56	    res.send(header + csv);
57	  } catch (e) { next(e); }
58	}
