1	import { DataTypes, Model } from 'sequelize';
2	import { sequelize } from '../config/database';
3	
4	export class AuditLog extends Model {
5	  public id!: string; public actor_id!: string | null; public action!: string;
6	  public resource_type!: string | null; public resource_id!: string | null;
7	  public detail!: Record<string, unknown> | null; public trace_id!: string | null;
8	  public ip_address!: string | null; public created_at!: Date;
9	}
10	AuditLog.init({
11	  id: { type: DataTypes.STRING(36), primaryKey: true },
12	  actor_id: { type: DataTypes.STRING(36), allowNull: true },
13	  action: { type: DataTypes.STRING(255), allowNull: false },
14	  resource_type: { type: DataTypes.STRING(100), allowNull: true },
15	  resource_id: { type: DataTypes.STRING(36), allowNull: true },
16	  detail: { type: DataTypes.JSON, allowNull: true },
17	  trace_id: { type: DataTypes.STRING(36), allowNull: true },
18	  ip_address: { type: DataTypes.STRING(45), allowNull: true },
19	  created_at: { type: DataTypes.DATE, allowNull: false },
20	}, { sequelize, tableName: 'audit_logs', timestamps: false, underscored: true });
21	
22	// Enforce immutability at app level ŌĆö no UPDATE or DELETE via Sequelize ORM.
23	// The archive retention job uses raw SQL which bypasses these hooks intentionally.
24	// This is the documented maintenance boundary: only raw SQL with elevated context
25	// (the cron archive job) can remove rows older than 1 year.
26	AuditLog.beforeUpdate(() => { throw new Error('Audit logs are immutable ŌĆö UPDATE is not allowed'); });
27	AuditLog.beforeDestroy(() => { throw new Error('Audit logs are immutable ŌĆö DELETE is not allowed'); });
28	AuditLog.beforeBulkUpdate(() => { throw new Error('Audit logs are immutable ŌĆö bulk UPDATE is not allowed'); });
29	AuditLog.beforeBulkDestroy(() => { throw new Error('Audit logs are immutable ŌĆö bulk DELETE is not allowed'); });
