1	import { v4 as uuidv4 } from 'uuid';
2	import ExcelJS from 'exceljs';
3	import { QueryTypes } from 'sequelize';
4	import { ImportBatch, ImportError, StaffingRecord, EvaluationRecord } from '../models/import.model';
5	import { AppError } from '../utils/errors';
6	import { sequelize } from '../config/database';
7	import { traceStore, createCategoryLogger } from '../utils/logger';
8	
9	const logger = createCategoryLogger('import');
10	
11	const STAFFING_COLUMNS = ['employee_id', 'effective_date', 'position', 'department', 'property_id', 'signed_off_by'];
12	const STAFFING_REQUIRED = ['employee_id', 'effective_date', 'position'];
13	const EVAL_COLUMNS = ['employee_id', 'effective_date', 'score', 'result', 'rewards', 'penalties', 'signed_off_by'];
14	const EVAL_REQUIRED = ['employee_id', 'effective_date', 'score', 'result'];
15	const MAX_RETRY_ATTEMPTS = 3;
16	
17	export async function getTemplate(datasetType: string): Promise<ExcelJS.Workbook> {
18	  const wb = new ExcelJS.Workbook();
19	  const ws = wb.addWorksheet(datasetType);
20	  ws.addRow(datasetType === 'staffing' ? STAFFING_COLUMNS : EVAL_COLUMNS);
21	  return wb;
22	}
23	
24	function parseRows(ws: ExcelJS.Worksheet, headers: string[], datasetType: string) {
25	  const errors: { rowNumber: number; field: string | null; reason: string }[] = [];
26	  const validRows: Record<string, string>[] = [];
27	  const required = datasetType === 'staffing' ? STAFFING_REQUIRED : EVAL_REQUIRED;
28	
29	  ws.eachRow((row, rowNum) => {
30	    if (rowNum === 1) return;
31	    const data: Record<string, string> = {};
32	    headers.forEach((h, i) => { data[h] = row.getCell(i + 1).text?.trim() || ''; });
33	
34	    let hasError = false;
35	    for (const req of required) {
36	      if (!data[req]) { errors.push({ rowNumber: rowNum, field: req, reason: `${req} is required` }); hasError = true; }
37	    }
38	    if (data.effective_date && !/^\d{4}-\d{2}-\d{2}$/.test(data.effective_date)) {
39	      errors.push({ rowNumber: rowNum, field: 'effective_date', reason: 'Must be YYYY-MM-DD' }); hasError = true;
40	    }
41	    if (datasetType === 'evaluation' && data.score && isNaN(Number(data.score))) {
42	      errors.push({ rowNumber: rowNum, field: 'score', reason: 'Must be a number' }); hasError = true;
43	    }
44	    if (!hasError) validRows.push(data);
45	  });
46	
47	  return { errors, validRows, totalRows: validRows.length + errors.length };
48	}
49	
50	export async function uploadAndValidate(userId: string, datasetType: string, buffer: Buffer) {
51	  const batchId = uuidv4();
52	  const traceId = traceStore.getStore()?.traceId || null;
53	
54	  const batch = await ImportBatch.create({
55	    id: batchId, user_id: userId, batch_type: datasetType,
56	    status: 'pending', trace_id: traceId, created_at: new Date(),
57	  });
58	
59	  const wb = new ExcelJS.Workbook();
60	  await wb.xlsx.load(buffer as unknown as ExcelJS.Buffer);
61	  const ws = wb.worksheets[0];
62	  if (!ws) throw new AppError(400, 'VALIDATION_ERROR', 'No worksheet found');
63	
64	  const headers = (ws.getRow(1).values as string[]).slice(1).map(h => String(h).trim().toLowerCase());
65	  const required = datasetType === 'staffing' ? STAFFING_REQUIRED : EVAL_REQUIRED;
66	  const missing = required.filter(r => !headers.includes(r));
67	  if (missing.length > 0) throw new AppError(400, 'VALIDATION_ERROR', `Missing required columns: ${missing.join(', ')}`);
68	
69	  const { errors, validRows, totalRows } = parseRows(ws, headers, datasetType);
70	
71	  for (const err of errors) {
72	    await ImportError.create({ id: uuidv4(), batch_id: batchId, row_number: err.rowNumber, field: err.field, reason: err.reason });
73	  }
74	
75	  // Store valid rows as JSON in batch for commit phase
76	  await ImportBatch.update({
77	    total_rows: totalRows, error_rows: errors.length,
78	    success_rows: validRows.length, status: 'pending',
79	  }, { where: { id: batchId } });
80	
81	  // Store parsed valid rows in a temp table approach ŌĆö we use import_errors with a special marker
82	  // Actually, store them serialized. Simpler: re-attach to batch via a data column.
83	  // For production grade, we store the valid rows in a JSON blob on the batch.
84	  // Since ImportBatch doesn't have a data column, we store in a temp file.
85	  if (validRows.length > 0) {
86	    const fs = require('fs');
87	    const pathMod = require('path');
88	    const tmpDir = pathMod.resolve('var/import-tmp');
89	    if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });
90	    fs.writeFileSync(pathMod.resolve(tmpDir, `.import-${batchId}.json`), JSON.stringify({ datasetType, validRows }));
91	  }
92	
93	  return { batchId, totalRows, validRows: validRows.length, errorRows: errors.length, errors };
94	}
95	
96	export async function commitBatch(batchId: string, userId: string) {
97	  const batch = await ImportBatch.findByPk(batchId);
98	  if (!batch) throw new AppError(404, 'NOT_FOUND', 'Batch not found');
99	  if (batch.user_id !== userId) throw new AppError(403, 'FORBIDDEN', 'Not authorized for this batch');
100	  if (batch.status === 'completed') throw new AppError(409, 'CONFLICT', 'Already committed');
101	  if (batch.status === 'failed') throw new AppError(409, 'CONFLICT', 'Batch failed');
102	
103	  const fs = require('fs');
104	  const pathMod = require('path');
105	  const dataPath = pathMod.resolve(`var/import-tmp/.import-${batchId}.json`);
106	
107	  let datasetType: string;
108	  let validRows: Record<string, string>[];
109	  try {
110	    const raw = fs.readFileSync(dataPath, 'utf8');
111	    const parsed = JSON.parse(raw);
112	    datasetType = parsed.datasetType;
113	    validRows = parsed.validRows;
114	  } catch {
115	    // No valid rows to commit
116	    await ImportBatch.update({ status: 'completed', completed_at: new Date() }, { where: { id: batchId } });
117	    return ImportBatch.findByPk(batchId);
118	  }
119	
120	  let attempt = 0;
121	  while (attempt < MAX_RETRY_ATTEMPTS) {
122	    attempt++;
123	    const t = await sequelize.transaction();
124	    try {
125	      await ImportBatch.update({ status: 'processing' }, { where: { id: batchId }, transaction: t });
126	
127	      let inserted = 0;
128	      for (const row of validRows) {
129	        if (datasetType === 'staffing') {
130	          // Upsert by (employee_id, effective_date)
131	          const existing = await StaffingRecord.findOne({
132	            where: { employee_id: row.employee_id, effective_date: row.effective_date },
133	            transaction: t,
134	          });
135	          if (existing) {
136	            await StaffingRecord.update({
137	              position: row.position,
138	              department: row.department || null,
139	              property_id: row.property_id || null,
140	              signed_off_by: row.signed_off_by || null,
141	              batch_id: batchId,
142	            }, { where: { id: existing.id }, transaction: t });
143	          } else {
144	            await StaffingRecord.create({
145	              id: uuidv4(), batch_id: batchId,
146	              employee_id: row.employee_id, effective_date: row.effective_date,
147	              position: row.position, department: row.department || null,
148	              property_id: row.property_id || null, signed_off_by: row.signed_off_by || null,
149	              created_at: new Date(),
150	            }, { transaction: t });
151	          }
152	          inserted++;
153	        } else {
154	          // evaluation ŌĆö upsert by (employee_id, effective_date)
155	          const existing = await EvaluationRecord.findOne({
156	            where: { employee_id: row.employee_id, effective_date: row.effective_date },
157	            transaction: t,
158	          });
159	          if (existing) {
160	            await EvaluationRecord.update({
161	              score: row.score ? Number(row.score) : null,
162	              result: row.result || null,
163	              rewards: row.rewards || null,
164	              penalties: row.penalties || null,
165	              signed_off_by: row.signed_off_by || null,
166	              batch_id: batchId,
167	            }, { where: { id: existing.id }, transaction: t });
168	          } else {
169	            await EvaluationRecord.create({
170	              id: uuidv4(), batch_id: batchId,
