13	// Hard-delete raw face images past 24h retention
14	async function cleanupFaceImages(): Promise<void> {
15	  try {
16	    const expired = await FaceEnrollment.findAll({
17	      where: {
18	        raw_image_path: { [Op.ne]: null },
19	        raw_image_expires_at: { [Op.lt]: new Date() },
20	      },
21	    });
22	
23	    for (const enrollment of expired) {
24	      if (enrollment.raw_image_path) {
25	        // raw_image_path may contain multiple paths separated by semicolons
26	        for (const imgPath of enrollment.raw_image_path.split(';')) {
27	          try { fs.unlinkSync(path.resolve(imgPath.trim())); } catch { /* already gone */ }
28	        }
29	      }
30	      await FaceEnrollment.update(
31	        { raw_image_path: null, raw_image_expires_at: null },
32	        { where: { id: enrollment.id } }
33	      );
34	    }
35	
36	    // Expire stale sessions (30 min)
37	    await FaceEnrollmentSession.update(
38	      { status: 'expired' },
39	      { where: { status: 'in_progress', expires_at: { [Op.lt]: new Date() } } }
40	    );
41	
42	    if (expired.length > 0) {
43	      logger.info('Face image cleanup completed', { deletedCount: expired.length });
44	    }
45	  } catch (err) {
46	    logger.error('Face image cleanup failed', { error: err instanceof Error ? err.message : String(err) });
47	  }
48	}
