50	// Delete generated export archives past 24h
51	async function cleanupExports(): Promise<void> {
52	  try {
53	    const exportsDir = path.resolve('exports');
54	    if (!fs.existsSync(exportsDir)) return;
55	
56	    const files = fs.readdirSync(exportsDir);
57	    const cutoff = Date.now() - 24 * 60 * 60 * 1000;
58	    let deletedCount = 0;
59	
60	    for (const file of files) {
61	      if (file === '.gitkeep') continue;
62	      const filePath = path.join(exportsDir, file);
63	      const stat = fs.statSync(filePath);
64	      if (stat.mtimeMs < cutoff) {
65	        fs.unlinkSync(filePath);
66	        deletedCount++;
67	      }
68	    }
69	
70	    if (deletedCount > 0) {
71	      logger.info('Export cleanup completed', { deletedCount });
72	    }
73	  } catch (err) {
74	    logger.error('Export cleanup failed', { error: err instanceof Error ? err.message : String(err) });
