120	export async function commitBatch(batchId: string, userId: string) {
121	  const batch = await ImportBatch.findByPk(batchId);
122	  if (!batch) throw new AppError(404, 'NOT_FOUND', 'Batch not found');
123	  if (batch.user_id !== userId) throw new AppError(403, 'FORBIDDEN', 'Not authorized for this batch');
124	  if (batch.status === 'completed') throw new AppError(409, 'CONFLICT', 'Already committed');
125	  if (batch.status === 'failed') throw new AppError(409, 'CONFLICT', 'Batch failed');
126	
127	  const dataPath = tmpFilePath(batchId);
128	
129	  let datasetType: string;
130	  let validRows: Record<string, string>[];
131	  try {
132	    const raw = fs.readFileSync(dataPath, 'utf8');
133	    const parsed = JSON.parse(raw);
134	    datasetType = parsed.datasetType;
135	    validRows = parsed.validRows;
136	  } catch {
137	    // No valid rows to commit
138	    await ImportBatch.update({ status: 'completed', completed_at: new Date() }, { where: { id: batchId } });
139	    return ImportBatch.findByPk(batchId);
140	  }
141	
142	  let attempt = 0;
143	  while (attempt < MAX_RETRY_ATTEMPTS) {
144	    attempt++;
145	    const t = await sequelize.transaction();
146	    try {
147	      await ImportBatch.update({ status: 'processing' }, { where: { id: batchId }, transaction: t });
148	
149	      let inserted = 0;
150	      for (const row of validRows) {
151	        if (datasetType === 'staffing') {
152	          // Upsert by (employee_id, effective_date)
153	          const existing = await StaffingRecord.findOne({
154	            where: { employee_id: row.employee_id, effective_date: row.effective_date },
155	            transaction: t,
156	          });
157	          if (existing) {
158	            await StaffingRecord.update({
159	              position: row.position,
