249	export async function evaluationReport(params: { propertyId?: string; from?: string; to?: string }) {
250	  // Evaluation records do not carry property_id directly; the property an
251	  // employee belongs to is derived from their staffing records. When a
252	  // property scope is supplied (manager path or explicit propertyId query
253	  // parameter), we filter evaluations down to employees who have at least
254	  // one staffing row on that property. This mirrors the strictness of
255	  // staffingReport's property filter and closes the manager isolation gap
256	  // reported in the static audit.
257	  const clauses: string[] = [];
258	  const replacements: (string | number)[] = [];
259	  if (params.propertyId) {
260	    clauses.push(
261	      'EXISTS (SELECT 1 FROM staffing_records s WHERE s.employee_id = e.employee_id AND s.property_id = ?)'
262	    );
263	    replacements.push(params.propertyId);
264	  }
265	  if (params.from) { clauses.push('e.effective_date >= ?'); replacements.push(params.from); }
266	  if (params.to) { clauses.push('e.effective_date <= ?'); replacements.push(params.to); }
267	  const where = clauses.length ? 'WHERE ' + clauses.join(' AND ') : '';
268	
269	  const summary = await sequelize.query(
270	    `SELECT result, COUNT(*) as count, AVG(score) as avg_score FROM evaluation_records e ${where} GROUP BY result ORDER BY count DESC`,
271	    { replacements, type: QueryTypes.SELECT }
272	  );
273	  return { resultsSummary: summary };
274	}
