6	function scopeWhere(params: ReportParams, managerPropertyId?: string): { clauses: string[]; replacements: unknown[] } {
7	  const clauses: string[] = [];
8	  const replacements: unknown[] = [];
9	  const propId = managerPropertyId || params.propertyId;
10	  if (propId) { clauses.push('r.property_id = ?'); replacements.push(propId); }
11	  clauses.push('r.check_in_date <= ?'); replacements.push(params.to);
12	  clauses.push('r.check_out_date >= ?'); replacements.push(params.from);
13	  if (params.roomType) { clauses.push('rm.room_type = ?'); replacements.push(params.roomType); }
14	  return { clauses, replacements };
15	}
16	
17	function roomCountSubquery(propId?: string): { sql: string; replacements: unknown[] } {
18	  if (propId) {
19	    return { sql: "(SELECT COUNT(*) FROM rooms rm2 WHERE rm2.status != 'maintenance' AND rm2.property_id = ?)", replacements: [propId] };
20	  }
21	  return { sql: "(SELECT COUNT(*) FROM rooms rm2 WHERE rm2.status != 'maintenance')", replacements: [] };
22	}
