24	function groupByExpr(groupBy: string): string {
25	  switch (groupBy) {
26	    case 'week': return "DATE_FORMAT(r.check_in_date, '%x-W%v')";
27	    case 'month': return "DATE_FORMAT(r.check_in_date, '%Y-%m')";
28	    default: return 'r.check_in_date';
29	  }
