5	export class AuditLog extends Model {
6	  public id!: string; public actor_id!: string | null; public action!: string;
7	  public resource_type!: string | null; public resource_id!: string | null;
8	  public detail!: Record<string, unknown> | null; public trace_id!: string | null;
9	  public ip_address!: string | null; public created_at!: Date;
10	}
11	AuditLog.init({
12	  id: { type: DataTypes.STRING(36), primaryKey: true },
13	  actor_id: { type: DataTypes.STRING(36), allowNull: true },
14	  action: { type: DataTypes.STRING(255), allowNull: false },
15	  resource_type: { type: DataTypes.STRING(100), allowNull: true },
16	  resource_id: { type: DataTypes.STRING(36), allowNull: true },
17	  detail: { type: DataTypes.JSON, allowNull: true },
18	  trace_id: { type: DataTypes.STRING(36), allowNull: true },
19	  ip_address: { type: DataTypes.STRING(45), allowNull: true },
20	  created_at: { type: DataTypes.DATE, allowNull: false },
21	}, { sequelize, tableName: 'audit_logs', timestamps: false, underscored: true });
22	
23	// ---------------------------------------------------------------------------
24	// Immutability enforcement
25	// ---------------------------------------------------------------------------
26	// Three layers defend the "1-year immutable audit log" requirement:
27	//
28	//   1) Sequelize lifecycle hooks (below) reject every UPDATE/DELETE attempt
29	//      that goes through the ORM, including bulk operations and instance
30	//      methods (`save`, `update`, `destroy`). This is the "normal path"
31	//      guarantee ŌĆö any business code that accidentally calls an update or
32	//      delete will fail loudly before SQL is ever emitted.
33	//
34	//   2) DB-level triggers installed by migration 017-audit-logs-immutability.js
35	//      reject UPDATE and DELETE statements regardless of source, so even
36	//      raw SQL executed through the same credential cannot mutate
37	//      historical rows.
38	//
39	//   3) Production DB role grants (documented in docs/audit-immutability.md)
40	//      REVOKE UPDATE and DELETE from the application user on audit_logs,
41	//      leaving only a dedicated maintenance role able to run the archival
42	//      job.
43	//
44	// Throwing AppError (not plain Error) lets the global error handler render
45	// a structured 500 response rather than leaking a stack trace.
46	
47	const immutabilityError = (op: string): AppError =>
48	  new AppError(500, 'AUDIT_IMMUTABLE', `Audit logs are immutable ŌĆö ${op} is not allowed`);
49	
50	AuditLog.beforeUpdate(() => { throw immutabilityError('UPDATE'); });
51	AuditLog.beforeDestroy(() => { throw immutabilityError('DELETE'); });
52	AuditLog.beforeBulkUpdate(() => { throw immutabilityError('bulk UPDATE'); });
53	AuditLog.beforeBulkDestroy(() => { throw immutabilityError('bulk DELETE'); });
54	AuditLog.beforeSave((instance: AuditLog) => {
55	  // A no-op save on an existing row would bypass beforeUpdate in some
56	  // sequelize versions ŌĆö defensively reject any save that is not a create.
57	  if (!instance.isNewRecord) throw immutabilityError('SAVE');
58	});
