234	/**
235	 * Remove stale import temp files that were written but never committed.
236	 * A file is stale when its mtime is older than `maxAgeMs` (default 24h).
237	 * Returns the number of files deleted. Safe to call with a missing tmp dir.
238	 */
239	export function cleanupStaleImportTmp(maxAgeMs: number = 24 * 60 * 60 * 1000): number {
240	  if (!fs.existsSync(IMPORT_TMP_DIR)) return 0;
241	  const cutoff = Date.now() - maxAgeMs;
242	  let deleted = 0;
243	  for (const name of fs.readdirSync(IMPORT_TMP_DIR)) {
244	    // Only touch files that match the batch temp pattern ŌĆö never other
245	    // files that may land here by accident.
246	    if (!name.startsWith('.import-') || !name.endsWith('.json')) continue;
247	    const full = path.join(IMPORT_TMP_DIR, name);
248	    try {
249	      const stat = fs.statSync(full);
250	      if (stat.mtimeMs < cutoff) {
251	        fs.unlinkSync(full);
252	        deleted++;
253	      }
254	    } catch { /* already gone */ }
255	  }
256	  return deleted;
257	}
