259	export async function staffingReport(params: { propertyId?: string; from?: string; to?: string }) {
260	  const clauses: string[] = [];
261	  const replacements: string[] = [];
262	  if (params.propertyId) { clauses.push('s.property_id = ?'); replacements.push(params.propertyId); }
263	  if (params.from) { clauses.push('s.effective_date >= ?'); replacements.push(params.from); }
264	  if (params.to) { clauses.push('s.effective_date <= ?'); replacements.push(params.to); }
265	  const where = clauses.length ? 'WHERE ' + clauses.join(' AND ') : '';
266	
267	  const distribution = await sequelize.query(
268	    `SELECT position, COUNT(*) as count FROM staffing_records s ${where} GROUP BY position ORDER BY count DESC`,
269	    { replacements, type: QueryTypes.SELECT }
270	  );
271	  return { positionDistribution: distribution };
272	}
273	
274	export async function evaluationReport(params: { propertyId?: string; from?: string; to?: string }) {
275	  // Evaluation records do not carry property_id directly; the property an
276	  // employee belongs to is derived from their staffing records. When a
277	  // property scope is supplied (manager path or explicit propertyId query
278	  // parameter), we filter evaluations down to employees who have at least
279	  // one staffing row on that property. This mirrors the strictness of
280	  // staffingReport's property filter and closes the manager isolation gap
281	  // reported in the static audit.
282	  const clauses: string[] = [];
283	  const replacements: (string | number)[] = [];
284	  if (params.propertyId) {
285	    clauses.push(
286	      'EXISTS (SELECT 1 FROM staffing_records s WHERE s.employee_id = e.employee_id AND s.property_id = ?)'
287	    );
288	    replacements.push(params.propertyId);
289	  }
290	  if (params.from) { clauses.push('e.effective_date >= ?'); replacements.push(params.from); }
291	  if (params.to) { clauses.push('e.effective_date <= ?'); replacements.push(params.to); }
292	  const where = clauses.length ? 'WHERE ' + clauses.join(' AND ') : '';
293	
294	  const summary = await sequelize.query(
295	    `SELECT result, COUNT(*) as count, AVG(score) as avg_score FROM evaluation_records e ${where} GROUP BY result ORDER BY count DESC`,
296	    { replacements, type: QueryTypes.SELECT }
297	  );
298	  return { resultsSummary: summary };
299	}
