1	import { v4 as uuidv4 } from 'uuid';
2	import { ItineraryItem, ItineraryCheckpoint, MemberCheckin } from '../models/itinerary.model';
3	import { GroupMember, GroupRequiredField, MemberFieldValue } from '../models/group.model';
4	import { AppError, ErrorCodes } from '../utils/errors';
5	import { emitNotification } from './notification.service';
6	import { checkIdempotency, storeIdempotency } from './idempotency.service';
7	import { sequelize } from '../config/database';
8	
9	const DATE_REGEX = /^(0[1-9]|1[0-2])\/(0[1-9]|[12]\d|3[01])\/\d{4}$/;
10	const TIME_REGEX = /^(0?[1-9]|1[0-2]):[0-5]\d\s?(AM|PM)$/i;
11	const MAX_NOTES = 2000;
12	const MAX_CHECKPOINTS = 30;
13	
14	function parseSortDate(dateStr: string, timeStr: string): Date | null {
15	  try {
16	    const [month, day, year] = dateStr.split('/').map(Number);
17	    const match = timeStr.match(/^(\d{1,2}):(\d{2})\s?(AM|PM)$/i);
18	    if (!match) return null;
19	    let hours = parseInt(match[1]);
20	    const minutes = parseInt(match[2]);
21	    const ampm = match[3].toUpperCase();
22	    if (ampm === 'PM' && hours !== 12) hours += 12;
23	    if (ampm === 'AM' && hours === 12) hours = 0;
24	    return new Date(year, month - 1, day, hours, minutes);
25	  } catch { return null; }
26	}
27	
28	function validateItem(data: { meetupDate?: string; meetupTime?: string; notes?: string }) {
29	  if (data.meetupDate && !DATE_REGEX.test(data.meetupDate))
30	    throw new AppError(400, 'VALIDATION_ERROR', 'meetupDate must be MM/DD/YYYY');
31	  if (data.meetupTime && !TIME_REGEX.test(data.meetupTime))
32	    throw new AppError(400, 'VALIDATION_ERROR', 'meetupTime must be HH:MM AM/PM (12-hour)');
33	  if (data.notes && data.notes.length > MAX_NOTES)
34	    throw new AppError(400, 'VALIDATION_ERROR', `notes max ${MAX_NOTES} characters`);
35	}
36	
37	async function assertGroupMember(groupId: string, userId: string) {
38	  const m = await GroupMember.findOne({ where: { group_id: groupId, user_id: userId } });
39	  if (!m) throw new AppError(403, 'FORBIDDEN', 'Not a member of this group');
40	  return m;
41	}
42	
43	async function assertGroupOwnerOrAdmin(groupId: string, userId: string) {
44	  const m = await assertGroupMember(groupId, userId);
45	  if (m.role !== 'owner' && m.role !== 'admin')
46	    throw new AppError(403, 'FORBIDDEN', 'Owner or admin role required');
47	  return m;
48	}
49	
50	export async function createItem(groupId: string, userId: string, data: {
51	  title: string; meetupDate: string; meetupTime: string; meetupLocation: string;
52	  notes?: string; idempotencyKey: string;
53	}) {
54	  await assertGroupMember(groupId, userId);
55	  validateItem(data);
56	
57	  // Idempotency: return existing if key matches
58	  const existing = await ItineraryItem.findOne({ where: { idempotency_key: data.idempotencyKey } });
59	  if (existing) return existing;
60	
61	  const t = await sequelize.transaction();
62	  try {
63	    const item = await ItineraryItem.create({
64	      id: uuidv4(), group_id: groupId, title: data.title,
65	      meetup_date: data.meetupDate, meetup_time: data.meetupTime,
66	      meetup_location: data.meetupLocation, notes: data.notes || null,
67	      meetup_sort_at: parseSortDate(data.meetupDate, data.meetupTime),
68	      created_by: userId, idempotency_key: data.idempotencyKey,
69	    }, { transaction: t });
70	    await t.commit();
71	
72	    await emitNotification({
73	      groupId, actorId: userId, eventType: 'item_created',
74	      resourceType: 'itinerary_item', resourceId: item.id,
75	      detail: { title: data.title }, idempotencyKey: `item_created:${item.id}`,
76	    });
77	    return item;
78	  } catch (err) { await t.rollback(); throw err; }
79	}
80	
81	export async function listItems(groupId: string, userId: string) {
82	  await assertGroupMember(groupId, userId);
83	  return ItineraryItem.findAll({
84	    where: { group_id: groupId },
85	    include: [{ model: ItineraryCheckpoint, as: 'checkpoints' }],
86	    order: [['meetup_sort_at', 'ASC'], ['created_at', 'ASC']],
87	  });
88	}
89	
90	export async function getItem(groupId: string, itemId: string, userId: string) {
91	  await assertGroupMember(groupId, userId);
92	  const item = await ItineraryItem.findOne({
93	    where: { id: itemId, group_id: groupId },
94	    include: [
95	      { model: ItineraryCheckpoint, as: 'checkpoints', order: [['position', 'ASC']] },
96	      { model: MemberCheckin, as: 'checkins' },
97	    ],
98	  });
99	  if (!item) throw new AppError(404, 'NOT_FOUND', 'Itinerary item not found');
100	  return item;
101	}
