103	export async function updateItem(groupId: string, itemId: string, userId: string, data: {
104	  title?: string; meetupDate?: string; meetupTime?: string; meetupLocation?: string;
105	  notes?: string; idempotencyKey: string;
106	}) {
107	  await assertGroupMember(groupId, userId);
108	  validateItem(data);
109	
110	  // Update idempotency: replay stored response if same key+body
111	  const replay = await checkIdempotency(data.idempotencyKey, userId, 'update_itinerary', data);
112	  if (replay) return replay as ItineraryItem;
113	
114	  const item = await ItineraryItem.findOne({ where: { id: itemId, group_id: groupId } });
115	  if (!item) throw new AppError(404, 'NOT_FOUND', 'Itinerary item not found');
116	
117	  const t = await sequelize.transaction();
118	  try {
119	    const updateData: Record<string, unknown> = {};
120	    if (data.title) updateData.title = data.title;
121	    if (data.meetupDate) updateData.meetup_date = data.meetupDate;
122	    if (data.meetupTime) updateData.meetup_time = data.meetupTime;
123	    if (data.meetupLocation) updateData.meetup_location = data.meetupLocation;
124	    if (data.notes !== undefined) updateData.notes = data.notes;
125	    const newDate = data.meetupDate || item.meetup_date;
126	    const newTime = data.meetupTime || item.meetup_time;
127	    updateData.meetup_sort_at = parseSortDate(newDate, newTime);
128	
129	    await ItineraryItem.update(updateData, { where: { id: itemId }, transaction: t });
130	    await t.commit();
131	
132	    await emitNotification({
133	      groupId, actorId: userId, eventType: 'item_updated',
134	      resourceType: 'itinerary_item', resourceId: itemId,
135	      detail: { fields: Object.keys(updateData) }, idempotencyKey: `item_updated:${itemId}:${Date.now()}`,
136	    });
137	    const result = await ItineraryItem.findByPk(itemId);
138	    await storeIdempotency(data.idempotencyKey, userId, 'update_itinerary', itemId, data, result?.toJSON());
139	    return result;
140	  } catch (err) { await t.rollback(); throw err; }
141	}
