143	export async function deleteItem(groupId: string, itemId: string, userId: string) {
144	  await assertGroupOwnerOrAdmin(groupId, userId);
145	  const item = await ItineraryItem.findOne({ where: { id: itemId, group_id: groupId } });
146	  if (!item) throw new AppError(404, 'NOT_FOUND', 'Itinerary item not found');
147	  await ItineraryItem.destroy({ where: { id: itemId } });
148	
149	  await emitNotification({
150	    groupId, actorId: userId, eventType: 'item_deleted',
151	    resourceType: 'itinerary_item', resourceId: itemId,
152	    detail: { title: item.title }, idempotencyKey: `item_deleted:${itemId}:${Date.now()}`,
153	  });
154	}
