156	// --- Checkpoints ---
157	export async function addCheckpoint(groupId: string, itemId: string, userId: string, data: { label: string; position: number; description?: string }) {
158	  await assertGroupMember(groupId, userId);
159	  const item = await ItineraryItem.findOne({ where: { id: itemId, group_id: groupId } });
160	  if (!item) throw new AppError(404, 'NOT_FOUND', 'Itinerary item not found');
161	
162	  const count = await ItineraryCheckpoint.count({ where: { item_id: itemId } });
163	  if (count >= MAX_CHECKPOINTS)
164	    throw new AppError(400, 'VALIDATION_ERROR', `Max ${MAX_CHECKPOINTS} checkpoints per item`);
165	
166	  if (data.position < 1 || data.position > MAX_CHECKPOINTS)
167	    throw new AppError(400, 'VALIDATION_ERROR', `Position must be 1-${MAX_CHECKPOINTS}`);
168	
169	  // Enforce unique position per item
170	  const conflict = await ItineraryCheckpoint.findOne({ where: { item_id: itemId, position: data.position } });
171	  if (conflict) throw new AppError(409, 'CONFLICT', `Position ${data.position} already occupied`);
172	
173	  return ItineraryCheckpoint.create({
174	    id: uuidv4(), item_id: itemId, position: data.position,
175	    label: data.label, description: data.description || null, created_at: new Date(),
176	  });
177	}
178	
179	export async function listCheckpoints(groupId: string, itemId: string, userId: string) {
180	  await assertGroupMember(groupId, userId);
181	  return ItineraryCheckpoint.findAll({ where: { item_id: itemId }, order: [['position', 'ASC']] });
182	}
183	
184	export async function updateCheckpoint(groupId: string, itemId: string, checkpointId: string, userId: string, data: { label?: string; position?: number; description?: string }) {
185	  await assertGroupMember(groupId, userId);
186	  const cp = await ItineraryCheckpoint.findOne({ where: { id: checkpointId, item_id: itemId } });
187	  if (!cp) throw new AppError(404, 'NOT_FOUND', 'Checkpoint not found');
188	  const updateData: Record<string, unknown> = {};
189	  if (data.label) updateData.label = data.label;
190	  if (data.description !== undefined) updateData.description = data.description;
191	  if (data.position !== undefined) {
192	    // Check position conflict
193	    const conflict = await ItineraryCheckpoint.findOne({ where: { item_id: itemId, position: data.position } });
194	    if (conflict && conflict.id !== checkpointId) throw new AppError(409, 'CONFLICT', `Position ${data.position} already occupied`);
195	    updateData.position = data.position;
196	  }
197	  await ItineraryCheckpoint.update(updateData, { where: { id: checkpointId } });
198	  return ItineraryCheckpoint.findByPk(checkpointId);
199	}
200	
201	export async function deleteCheckpoint(groupId: string, itemId: string, checkpointId: string, userId: string) {
202	  await assertGroupOwnerOrAdmin(groupId, userId);
203	  const cp = await ItineraryCheckpoint.findOne({ where: { id: checkpointId, item_id: itemId } });
204	  if (!cp) throw new AppError(404, 'NOT_FOUND', 'Checkpoint not found');
205	  await ItineraryCheckpoint.destroy({ where: { id: checkpointId } });
206	}
207	
208	// --- Check-in ---
209	export async function checkin(groupId: string, itemId: string, userId: string) {
210	  await assertGroupMember(groupId, userId);
211	  const item = await ItineraryItem.findOne({ where: { id: itemId, group_id: groupId } });
212	  if (!item) throw new AppError(404, 'NOT_FOUND', 'Itinerary item not found');
213	
214	  // Check required fields
215	  const requiredFields = await GroupRequiredField.findAll({ where: { group_id: groupId, is_required: true } });
216	  if (requiredFields.length > 0) {
217	    const values = await MemberFieldValue.findAll({ where: { group_id: groupId, user_id: userId } });
218	    const valueMap = new Map(values.map(v => [v.field_name, v.value]));
219	    const missing = requiredFields.filter(f => !valueMap.has(f.field_name) || !valueMap.get(f.field_name)).map(f => f.field_name);
220	    if (missing.length > 0)
221	      throw new AppError(400, 'MISSING_REQUIRED_FIELDS', `Missing required fields: ${missing.join(', ')}`);
222	  }
223	
224	  const existing = await MemberCheckin.findOne({ where: { item_id: itemId, user_id: userId } });
225	  if (existing) return existing;
226	
227	  return MemberCheckin.create({ id: uuidv4(), item_id: itemId, user_id: userId, checked_in_at: new Date() });
228	}
