1	import { QueryTypes } from 'sequelize';
2	import { sequelize } from '../config/database';
3	
4	interface ReportParams { propertyId?: string; from: string; to: string; groupBy?: string; roomType?: string; }
5	
6	function scopeWhere(params: ReportParams, managerPropertyId?: string): { clauses: string[]; replacements: unknown[] } {
7	  const clauses: string[] = [];
8	  const replacements: unknown[] = [];
9	  const propId = managerPropertyId || params.propertyId;
10	  if (propId) { clauses.push('r.property_id = ?'); replacements.push(propId); }
11	  clauses.push('r.check_in_date <= ?'); replacements.push(params.to);
12	  clauses.push('r.check_out_date >= ?'); replacements.push(params.from);
13	  if (params.roomType) { clauses.push('rm.room_type = ?'); replacements.push(params.roomType); }
14	  return { clauses, replacements };
15	}
16	
17	function roomCountSubquery(propId?: string): { sql: string; replacements: unknown[] } {
18	  if (propId) {
19	    return { sql: "(SELECT COUNT(*) FROM rooms rm2 WHERE rm2.status != 'maintenance' AND rm2.property_id = ?)", replacements: [propId] };
20	  }
21	  return { sql: "(SELECT COUNT(*) FROM rooms rm2 WHERE rm2.status != 'maintenance')", replacements: [] };
22	}
23	
24	function groupByExpr(groupBy: string): string {
25	  switch (groupBy) {
26	    case 'week': return "DATE_FORMAT(r.check_in_date, '%x-W%v')";
27	    case 'month': return "DATE_FORMAT(r.check_in_date, '%Y-%m')";
28	    default: return 'r.check_in_date';
29	  }
30	}
31	
32	export async function occupancy(params: ReportParams, managerPropertyId?: string) {
33	  const gb = groupByExpr(params.groupBy || 'day');
34	  const { clauses, replacements } = scopeWhere(params, managerPropertyId);
35	  clauses.push("r.status IN ('confirmed','checked_in','checked_out')");
36	  const where = 'WHERE ' + clauses.join(' AND ');
37	
38	  const rc = roomCountSubquery(managerPropertyId || params.propertyId);
39	  const allReplacements = [...rc.replacements, ...replacements];
40	
41	  const sql = `SELECT ${gb} as period, COUNT(DISTINCT r.room_id) as occupied_rooms, ${rc.sql} as total_rooms
42	    FROM reservations r LEFT JOIN rooms rm ON r.room_id = rm.id ${where} GROUP BY period ORDER BY period`;
43	  return sequelize.query(sql, { replacements: allReplacements, type: QueryTypes.SELECT });
44	}
