78	    let data: unknown[];
79	    switch (reportType) {
80	      case 'occupancy': data = await reportingService.occupancy({ propertyId, from, to, groupBy }, scope); break;
81	      case 'adr': data = await reportingService.adr({ propertyId, from, to, groupBy }, scope); break;
