105	      // quotes) and values that begin with formula-trigger characters
106	      // (=, +, -, @) are neutralized against spreadsheet formula
107	      // injection. See src/utils/csv.ts.
108	      filename = `report-${reportType}-${exportId}.csv`;
109	      filePath = path.resolve('exports', filename);
110	      fs.writeFileSync(filePath, serializeReportRowsToCsv(rows));
111	    }
112	
113	    // Log export metadata to audit_logs
114	    await AuditLog.create({
115	      id: uuidv4(),
116	      actor_id: req.user!.id,
117	      action: 'report_export',
118	      resource_type: 'report',
119	      resource_id: exportId,
120	      detail: { reportType, from, to, format, groupBy, propertyId, includePii: !!includePii, rowCount: rows.length },
121	      trace_id: traceStore.getStore()?.traceId || null,
122	      ip_address: req.ip || null,
123	      created_at: new Date(),
124	    });
125	
126	    // Register export ownership
