128	      id: exportId, user_id: req.user!.id, filename,
129	      export_type: 'report',
130	      expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000),
131	      created_at: new Date(),
132	    });
133	
134	    res.json({ downloadUrl: `/exports/${filename}`, format: format === 'excel' ? 'xlsx' : 'csv' });
135	  } catch (e) { next(e); }
136	}
