1	// Mock Model class for unit tests
2	export class Model {
3	  static init = jest.fn();
4	  static findOne = jest.fn();
5	  static findByPk = jest.fn();
6	  static findAll = jest.fn();
7	  static findAndCountAll = jest.fn();
8	  static create = jest.fn();
9	  static update = jest.fn();
10	  static destroy = jest.fn();
11	  static belongsTo = jest.fn();
12	  static hasMany = jest.fn();
13	
14	  // Lifecycle hook registration. Real sequelize accumulates listeners on
15	  // the class-level hook registry; tests inspect them via
16	  // `(Model as any).options.hooks[name]`. The mock mirrors that shape so
17	  // app-level immutability tests can verify hooks fire as expected. Each
18	  // subclass gets its OWN `options` object the first time it registers a
19	  // hook so different models' hooks do not bleed into each other.
20	  static options: { hooks: Record<string, Function[]> } = { hooks: {} };
21	
22	  private static registerHook(name: string, fn: Function): void {
23	    // If the subclass inherits `options` from a parent, copy it so we
24	    // don't mutate the parent's hook registry.
25	    if (!Object.prototype.hasOwnProperty.call(this, 'options')) {
26	      (this as any).options = { hooks: {} };
27	    }
28	    const opts = (this as any).options as { hooks: Record<string, Function[]> };
29	    (opts.hooks[name] ||= []).push(fn);
30	  }
31	  static beforeUpdate(fn: Function): void { this.registerHook('beforeUpdate', fn); }
32	  static beforeDestroy(fn: Function): void { this.registerHook('beforeDestroy', fn); }
33	  static beforeBulkUpdate(fn: Function): void { this.registerHook('beforeBulkUpdate', fn); }
34	  static beforeBulkDestroy(fn: Function): void { this.registerHook('beforeBulkDestroy', fn); }
35	  static beforeSave(fn: Function): void { this.registerHook('beforeSave', fn); }
36	
37	  toJSON() { return {}; }
38	}
39	
40	// Optional is just a type ŌĆö export a no-op
41	export type Optional<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;
42	
43	export class Sequelize {
44	  authenticate = jest.fn().mockResolvedValue(undefined);
45	  define = jest.fn();
46	  sync = jest.fn().mockResolvedValue(undefined);
47	  transaction = jest.fn();
48	  close = jest.fn().mockResolvedValue(undefined);
49	  // Default shape for QueryTypes.SELECT is an array of row objects.
50	  // Individual tests can override via
51	  //   (sequelize.query as jest.Mock).mockResolvedValueOnce([...])
52	  query = jest.fn().mockResolvedValue([]);
53	}
54	
55	// Mirror the real database.ts exports so modules that import them through
56	// the jest moduleNameMapper shim get a working API surface in unit tests.
57	export const sequelize = new Sequelize();
58	
59	export async function testConnection(): Promise<void> {
60	  await sequelize.authenticate();
61	}
62	
63	/**
64	 * Shim of createAuditMaintainerConnection ŌĆö the real implementation lives
65	 * in src/config/database.ts and opens a second MySQL pool. In unit tests
66	 * we only care about the env-var branching behavior, so we replicate the
67	 * check here and return a fresh mock Sequelize instance (or null).
68	 */
69	export function createAuditMaintainerConnection(): Sequelize | null {
70	  const user = process.env.AUDIT_MAINTAINER_USER;
71	  const password = process.env.AUDIT_MAINTAINER_PASSWORD;
72	  if (!user || !password) return null;
73	  return new Sequelize();
74	}
75	
76	// QueryTypes mirror sequelize's enum so code that imports them
77	// (e.g. `import { QueryTypes } from 'sequelize'`) still compiles.
78	export const QueryTypes = {
79	  SELECT: 'SELECT',
80	  INSERT: 'INSERT',
81	  UPDATE: 'UPDATE',
82	  DELETE: 'DELETE',
83	  BULKUPDATE: 'BULKUPDATE',
84	  BULKDELETE: 'BULKDELETE',
85	  RAW: 'RAW',
86	} as const;
87	
