    /* eslint-disable no-console */
    console.error('============================================================');
    console.error('FATAL: Insecure production configuration detected.');
    for (const p of problems) console.error('  -', p);
    console.error('============================================================');
    /* eslint-enable no-console */
    throw new ConfigValidationError(problems);
  }
}
