1	import crypto from 'crypto';
2	import { v4 as uuidv4 } from 'uuid';
3	import { ItineraryItem, ItineraryCheckpoint, MemberCheckin } from '../models/itinerary.model';
4	import { GroupMember, GroupRequiredField, MemberFieldValue } from '../models/group.model';
5	import { AppError, ErrorCodes } from '../utils/errors';
