10	// Hash the relevant create-payload fields for idempotency conflict
11	// detection. We deliberately exclude `idempotencyKey` itself so two
12	// requests with the same key always match by content alone.
13	function hashCreateBody(data: { title: string; meetupDate: string; meetupTime: string; meetupLocation: string; notes?: string }): string {
14	  const normalized = JSON.stringify({
15	    title: data.title,
16	    meetupDate: data.meetupDate,
17	    meetupTime: data.meetupTime,
18	    meetupLocation: data.meetupLocation,
19	    notes: data.notes ?? null,
20	  });
21	  return crypto.createHash('sha256').update(normalized).digest('hex');
22	}
23	
24	const DATE_REGEX = /^(0[1-9]|1[0-2])\/(0[1-9]|[12]\d|3[01])\/\d{4}$/;
25	const TIME_REGEX = /^(0?[1-9]|1[0-2]):[0-5]\d\s?(AM|PM)$/i;
26	const MAX_NOTES = 2000;
27	const MAX_CHECKPOINTS = 30;
28	
29	function parseSortDate(dateStr: string, timeStr: string): Date | null {
30	  try {
31	    const [month, day, year] = dateStr.split('/').map(Number);
32	    const match = timeStr.match(/^(\d{1,2}):(\d{2})\s?(AM|PM)$/i);
33	    if (!match) return null;
34	    let hours = parseInt(match[1]);
35	    const minutes = parseInt(match[2]);
36	    const ampm = match[3].toUpperCase();
37	    if (ampm === 'PM' && hours !== 12) hours += 12;
38	    if (ampm === 'AM' && hours === 12) hours = 0;
39	    return new Date(year, month - 1, day, hours, minutes);
40	  } catch { return null; }
41	}
42	
43	function validateItem(data: { meetupDate?: string; meetupTime?: string; notes?: string }) {
44	  if (data.meetupDate && !DATE_REGEX.test(data.meetupDate))
45	    throw new AppError(400, 'VALIDATION_ERROR', 'meetupDate must be MM/DD/YYYY');
46	  if (data.meetupTime && !TIME_REGEX.test(data.meetupTime))
47	    throw new AppError(400, 'VALIDATION_ERROR', 'meetupTime must be HH:MM AM/PM (12-hour)');
48	  if (data.notes && data.notes.length > MAX_NOTES)
49	    throw new AppError(400, 'VALIDATION_ERROR', `notes max ${MAX_NOTES} characters`);
50	}
51	
52	async function assertGroupMember(groupId: string, userId: string) {
53	  const m = await GroupMember.findOne({ where: { group_id: groupId, user_id: userId } });
54	  if (!m) throw new AppError(403, 'FORBIDDEN', 'Not a member of this group');
55	  return m;
56	}
57	
58	async function assertGroupOwnerOrAdmin(groupId: string, userId: string) {
59	  const m = await assertGroupMember(groupId, userId);
60	  if (m.role !== 'owner' && m.role !== 'admin')
61	    throw new AppError(403, 'FORBIDDEN', 'Owner or admin role required');
62	  return m;
63	}
64	
65	export async function createItem(groupId: string, userId: string, data: {
66	  title: string; meetupDate: string; meetupTime: string; meetupLocation: string;
67	  notes?: string; idempotencyKey: string;
68	}) {
69	  await assertGroupMember(groupId, userId);
70	  validateItem(data);
71	
72	  // Idempotency lookup is strictly scoped to (group_id, created_by,
73	  // idempotency_key) so a key reused across groups or across users is
74	  // never matched as a "replay" of a foreign item. This matches the
75	  // composite unique index installed by migration 018.
76	  const existing = await ItineraryItem.findOne({
77	    where: {
78	      group_id: groupId,
79	      created_by: userId,
80	      idempotency_key: data.idempotencyKey,
81	    },
82	  });
83	  if (existing) {
84	    // Replay only if the request body matches the original. A repeat
85	    // request with the same key but a different payload is a 409 ŌĆö it
86	    // signals client confusion, not a retry, and silently returning
87	    // the old item would lose data.
88	    const existingHash = hashCreateBody({
89	      title: existing.title,
90	      meetupDate: existing.meetup_date,
91	      meetupTime: existing.meetup_time,
92	      meetupLocation: existing.meetup_location,
93	      notes: existing.notes ?? undefined,
94	    });
95	    if (existingHash !== hashCreateBody(data)) {
96	      throw new AppError(
97	        409,
98	        'IDEMPOTENCY_CONFLICT',
99	        'Idempotency key already used with a different request body'
100	      );
101	    }
102	    return existing;
103	  }
104	
105	  const t = await sequelize.transaction();
106	  try {
107	    const item = await ItineraryItem.create({
108	      id: uuidv4(), group_id: groupId, title: data.title,
109	      meetup_date: data.meetupDate, meetup_time: data.meetupTime,
110	      meetup_location: data.meetupLocation, notes: data.notes || null,
111	      meetup_sort_at: parseSortDate(data.meetupDate, data.meetupTime),
112	      created_by: userId, idempotency_key: data.idempotencyKey,
113	    }, { transaction: t });
114	    await t.commit();
115	
116	    await emitNotification({
117	      groupId, actorId: userId, eventType: 'item_created',
118	      resourceType: 'itinerary_item', resourceId: item.id,
119	      detail: { title: data.title }, idempotencyKey: `item_created:${item.id}`,
120	    });
121	    return item;
122	  } catch (err) {
123	    await t.rollback();
124	    // If the unique index races (two concurrent identical requests
125	    // from the same scope), the second will hit the index and we
126	    // should re-fetch and replay rather than crash. Sequelize raises
127	    // SequelizeUniqueConstraintError for this case.
128	    const errName = (err as { name?: string })?.name;
129	    if (errName === 'SequelizeUniqueConstraintError') {
130	      const raced = await ItineraryItem.findOne({
131	        where: {
132	          group_id: groupId,
133	          created_by: userId,
134	          idempotency_key: data.idempotencyKey,
135	        },
136	      });
137	      if (raced) return raced;
138	    }
139	    throw err;
140	  }
141	}
