143	export async function listItems(groupId: string, userId: string) {
144	  await assertGroupMember(groupId, userId);
145	  return ItineraryItem.findAll({
146	    where: { group_id: groupId },
147	    include: [{ model: ItineraryCheckpoint, as: 'checkpoints' }],
148	    order: [['meetup_sort_at', 'ASC'], ['created_at', 'ASC']],
149	  });
