1	/**
2	 * Unit tests for the room-night reporting SQL builder.
3	 *
4	 * These tests spy on `sequelize.query` and assert structural properties
5	 * of the generated SQL ŌĆö they would fail loudly if the room-night
6	 * fix were ever silently reverted.
7	 */
8	
9	import { sequelize } from '../src/config/database';
10	import { occupancy, adr, revpar } from '../src/services/reporting.service';
11	
12	describe('reporting service ŌĆö SQL fragment shape', () => {
13	  beforeEach(() => {
14	    (sequelize.query as jest.Mock).mockReset().mockResolvedValue([]);
15	  });
16	
17	  function lastSql(): string {
18	    return (sequelize.query as jest.Mock).mock.calls[0][0] as string;
19	  }
20	
21	  function lastReplacements(): unknown[] {
22	    return ((sequelize.query as jest.Mock).mock.calls[0][1] as { replacements: unknown[] }).replacements;
23	  }
24	
25	  describe('occupancy', () => {
26	    test('contains recursive calendar CTE', async () => {
27	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
28	      expect(lastSql()).toMatch(/WITH RECURSIVE calendar/);
29	    });
30	
31	    test('uses check-in inclusive, check-out exclusive', async () => {
32	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
33	      const sql = lastSql();
34	      expect(sql).toMatch(/cal\.night >= res\.check_in_date/);
35	      expect(sql).toMatch(/cal\.night <\s+res\.check_out_date/);
36	    });
37	
38	    test('excludes maintenance rooms from available count', async () => {
39	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
40	      expect(lastSql()).toMatch(/rm\.status <> 'maintenance'/);
41	    });
42	
43	    test('includes occupancy_rate column in output', async () => {
44	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
45	      expect(lastSql()).toMatch(/occupancy_rate/);
46	    });
47	
48	    test('NULLIF guards against zero available rooms', async () => {
49	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
50	      expect(lastSql()).toMatch(/NULLIF\(SUM\(available_rooms\), 0\)/);
51	    });
52	
53	    test('excludes cancelled reservations', async () => {
54	      await occupancy({ from: '2026-06-01', to: '2026-06-03' });
55	      const sql = lastSql();
56	      expect(sql).toMatch(/res\.status IN \('confirmed','checked_in','checked_out'\)/);
57	      expect(sql).not.toMatch(/'cancelled'/);
58	    });
59	
60	    test('manager scope override takes precedence over caller propertyId', async () => {
61	      await occupancy({ from: '2026-06-01', to: '2026-06-03', propertyId: 'caller-prop' }, 'manager-prop');
62	      const reps = lastReplacements();
63	      expect(reps).toContain('manager-prop');
64	      expect(reps).not.toContain('caller-prop');
65	    });
66	
67	    test('room type filter is positional and replicated for both subqueries', async () => {
68	      await occupancy({ from: '2026-06-01', to: '2026-06-03', roomType: 'suite' });
69	      const reps = lastReplacements();
70	      // 'suite' should appear in both available and occupied filters
71	      const occ = reps.filter(r => r === 'suite').length;
72	      expect(occ).toBe(2);
73	    });
74	
75	    test('day grouping uses YYYY-MM-DD format', async () => {
76	      await occupancy({ from: '2026-06-01', to: '2026-06-03', groupBy: 'day' });
77	      expect(lastSql()).toMatch(/DATE_FORMAT\(night, '%Y-%m-%d'\)/);
78	    });
79	
80	    test('week grouping uses ISO week format', async () => {
81	      await occupancy({ from: '2026-06-01', to: '2026-06-03', groupBy: 'week' });
82	      expect(lastSql()).toMatch(/DATE_FORMAT\(night, '%x-W%v'\)/);
83	    });
84	
85	    test('month grouping uses YYYY-MM format', async () => {
86	      await occupancy({ from: '2026-06-01', to: '2026-06-03', groupBy: 'month' });
87	      expect(lastSql()).toMatch(/DATE_FORMAT\(night, '%Y-%m'\)/);
88	    });
89	  });
90	
91	  describe('adr', () => {
92	    test('formula is revenue / occupied (room-nights)', async () => {
93	      await adr({ from: '2026-06-01', to: '2026-06-03' });
94	      expect(lastSql()).toMatch(/SUM\(revenue_cents\)\s*\/\s*NULLIF\(SUM\(occupied_rooms\), 0\)/);
95	    });
96	  });
97	
98	  describe('revpar', () => {
99	    test('formula is revenue / available (room-nights)', async () => {
100	      await revpar({ from: '2026-06-01', to: '2026-06-03' });
101	      expect(lastSql()).toMatch(/SUM\(revenue_cents\)\s*\/\s*NULLIF\(SUM\(available_rooms\), 0\)/);
102	    });
103	  });
104	});
