1	/**
2	 * Unit tests for production environment validation.
3	 *
4	 * The fail-fast validator in src/config/environment.ts is the only
5	 * thing standing between a misconfigured production deployment and
6	 * an audit-grade compromise. These tests pin its behavior:
7	 *
8	 *  - default JWT_SECRET / ENCRYPTION_KEY ŌåÆ reject
9	 *  - any value in the KNOWN_WEAK_SECRETS set ŌåÆ reject
10	 *  - too-short value ŌåÆ reject
11	 *  - default DB_PASSWORD ŌåÆ reject
12	 *  - strong values ŌåÆ accept
13	 */
14	
15	import { validateProductionConfig, ConfigValidationError } from '../src/config/environment';
16	
17	function strong(len = 64): string {
18	  // 'a' x 64 ŌĆö meets the length floor without being a known weak value
19	  return 'a'.repeat(len);
20	}
21	
22	function baseCfg(over: Partial<any> = {}): any {
23	  return {
24	    port: 3000,
25	    nodeEnv: 'production',
26	    db: { host: 'db', port: 3306, user: 'app', password: 'StrongDbPassword!', name: 'hospitality' },
27	    auditMaintainer: { user: null, password: null },
28	    jwtSecret: strong(),
29	    encryptionKey: strong(),
30	    jwtTtl: 28800,
31	    face: { blinkMin: 100, blinkMax: 500, motionMin: 0.6, textureMin: 0.5 },
32	    ...over,
33	  };
34	}
35	
36	describe('validateProductionConfig', () => {
37	  test('passes with strong values', () => {
38	    expect(validateProductionConfig(baseCfg())).toEqual([]);
39	  });
40	
41	  test('rejects default JWT_SECRET', () => {
42	    const problems = validateProductionConfig(baseCfg({ jwtSecret: 'change_me_in_production' }));
43	    expect(problems.some((p) => p.includes('JWT_SECRET') && p.includes('insecure default'))).toBe(true);
44	  });
45	
46	  test('rejects default ENCRYPTION_KEY', () => {
47	    const problems = validateProductionConfig(baseCfg({ encryptionKey: 'change_me_32_chars_minimum_here_x' }));
48	    expect(problems.some((p) => p.includes('ENCRYPTION_KEY') && p.includes('insecure default'))).toBe(true);
49	  });
50	
51	  test('rejects empty JWT_SECRET', () => {
52	    expect(validateProductionConfig(baseCfg({ jwtSecret: '' })).length).toBeGreaterThan(0);
53	  });
54	
55	  test('rejects empty ENCRYPTION_KEY', () => {
56	    expect(validateProductionConfig(baseCfg({ encryptionKey: '' })).length).toBeGreaterThan(0);
57	  });
58	
59	  test('rejects short JWT_SECRET (length < 32)', () => {
60	    const problems = validateProductionConfig(baseCfg({ jwtSecret: 'short-but-not-default-1' }));
61	    expect(problems.some((p) => p.includes('JWT_SECRET') && p.includes('at least 32'))).toBe(true);
62	  });
63	
64	  test('rejects short ENCRYPTION_KEY', () => {
65	    const problems = validateProductionConfig(baseCfg({ encryptionKey: 'still-too-short-1' }));
66	    expect(problems.some((p) => p.includes('ENCRYPTION_KEY') && p.includes('at least 32'))).toBe(true);
67	  });
68	
69	  test('rejects default DB_PASSWORD', () => {
70	    const problems = validateProductionConfig(baseCfg({ db: { ...baseCfg().db, password: 'hospitality' } }));
71	    expect(problems.some((p) => p.includes('DB_PASSWORD'))).toBe(true);
72	  });
73	
74	  test('rejects empty DB_PASSWORD', () => {
75	    const problems = validateProductionConfig(baseCfg({ db: { ...baseCfg().db, password: '' } }));
76	    expect(problems.some((p) => p.includes('DB_PASSWORD'))).toBe(true);
77	  });
78	
79	  test('common weak words are blocked', () => {
80	    for (const weak of ['secret', 'password', 'changeme', 'test', 'default']) {
81	      const problems = validateProductionConfig(baseCfg({ jwtSecret: weak }));
82	      expect(problems.length).toBeGreaterThan(0);
83	    }
84	  });
85	
86	  test('aggregates multiple problems into a single error message', () => {
87	    const problems = validateProductionConfig(baseCfg({
