1	/**
2	 * Unit tests for production error log sanitization.
3	 *
4	 * The global error handler in src/app.ts strips raw error messages and
5	 * stack traces from both the log entry and the HTTP response body
6	 * when NODE_ENV=production. These tests build a tiny isolated express
7	 * app that mirrors the global handler logic and assert that:
8	 *
9	 *  - non-prod logs include `stack` and `error`
10	 *  - prod logs do NOT include `stack` or `error`
11	 *  - prod responses return generic 500 messages
12	 *  - non-prod responses surface the underlying error message
13	 *
14	 * We use a mirrored handler so the test does not need the full app's
15	 * route surface or DB. The handler under test is the same shape as
16	 * the one in src/app.ts.
17	 */
18	
19	import express, { Request, Response, NextFunction } from 'express';
20	import request from 'supertest';
21	import { AppError } from '../src/utils/errors';
22	
23	interface LogEntry { message: string; meta: Record<string, unknown> }
24	
25	function makeApp(nodeEnv: 'production' | 'development', sink: LogEntry[]) {
26	  const app = express();
27	  app.get('/boom', (_req: Request, _res: Response, next: NextFunction) => {
28	    next(new Error('SECRET_VALUE_LEAK_token=abc123'));
29	  });
30	  app.get('/app-error', (_req: Request, _res: Response, next: NextFunction) => {
31	    next(new AppError(404, 'NOT_FOUND', 'thing not found'));
32	  });
33	  const isProd = nodeEnv === 'production';
34	  app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
35	    if (err instanceof AppError) {
36	      res.status(err.statusCode).json({
37	        statusCode: err.statusCode, code: err.code, message: err.message, traceId: 'test',
38	      });
39	      return;
40	    }
41	    sink.push({
42	      message: 'unhandled_error',
43	      meta: {
44	        traceId: 'test',
45	        errorClass: err.constructor?.name || 'Error',
46	        ...(isProd ? {} : { error: err.message, stack: err.stack }),
47	      },
48	    });
49	    res.status(500).json({
50	      statusCode: 500,
51	      code: 'INTERNAL_ERROR',
52	      message: isProd ? 'Internal server error' : (err.message || 'Internal server error'),
53	      traceId: 'test',
54	    });
55	  });
56	  return app;
57	}
