59	describe('global error handler ŌĆö sanitization in production', () => {
60	  test('non-production: response message + log stack include the raw error', async () => {
61	    const sink: LogEntry[] = [];
62	    const app = makeApp('development', sink);
63	    const res = await request(app).get('/boom');
64	    expect(res.status).toBe(500);
65	    expect(res.body.code).toBe('INTERNAL_ERROR');
66	    // Dev: full message exposed
67	    expect(res.body.message).toContain('SECRET_VALUE_LEAK_token=abc123');
